import{_,C as n,o as u,c as h,E as a,a2 as d,w as r,a as t,j as o}from"./chunks/framework.C24VBsJ9.js";const x=JSON.parse('{"title":"设备树基础教程","description":"","frontmatter":{"title":"设备树基础教程"},"headers":[],"relativePath":"tutorial/driver/01_device_tree_base/index.md","filePath":"tutorial/driver/01_device_tree_base/index.md","lastUpdated":1781674711000}'),m={name:"tutorial/driver/01_device_tree_base/index.md"};function p(f,e,c,b,q,g){const s=n("PageHeader"),i=n("ChapterLink"),l=n("ChapterNav");return u(),h("div",null,[a(s,{icon:"🌳",title:"设备树基础",description:"掌握设备树原理、语法和 OF API，从硬编码驱动迈向现代 Linux 驱动架构"}),e[14]||(e[14]=d('<h2 id="前言-为什么我们必须学习设备树" tabindex="-1">前言：为什么我们必须学习设备树 <a class="header-anchor" href="#前言-为什么我们必须学习设备树" aria-label="Permalink to &quot;前言：为什么我们必须学习设备树&quot;">​</a></h2><p>说实话，在嵌入式Linux驱动开发这条路上，设备树是一道绕不过去的坎。我见过不少朋友在字符设备驱动教程里摸爬滚打了几个月，觉得自己已经掌握了驱动开发的核心技能，结果一上手真实项目就傻眼了——人家代码里全是 <code>of_find_node_by_path</code>、<code>of_property_read_u32</code> 这种函数，设备树文件一大堆，完全不知道从哪里下手。</p><p>这其实不是你的问题，而是学习路径的问题。传统的驱动教程往往把设备树当成一个&quot;高级话题&quot;，放在后面讲，或者干脆不讲。但在实际工程中，设备树是基础中的基础——你不理解设备树，就没法真正理解现代Linux驱动的架构设计。</p><p>所以我们在完成字符设备驱动基础教程之后，紧接着就推出了这套设备树基础教程。它的目标非常明确：让你从零开始，系统性地掌握设备树的原理、语法、API和实战应用。当你学完这套教程，再去看那些厂商的驱动代码，你会发现它们其实没那么神秘。</p><h2 id="与00-chardev-base教程的关系" tabindex="-1">与00_chardev_base教程的关系 <a class="header-anchor" href="#与00-chardev-base教程的关系" aria-label="Permalink to &quot;与00_chardev_base教程的关系&quot;">​</a></h2><p>这套教程是00_chardev_base教程的延续和深化。在字符设备驱动教程里，我们主要关注的是&quot;怎么写一个字符设备驱动&quot;，而设备树教程关注的是&quot;怎么用设备树来描述硬件信息&quot;。</p><ul><li><p><strong>00_chardev_base</strong>：教你如何实现一个字符设备驱动，包括file_operations、设备号管理、内核模块机制等基础内容。在这个阶段，我们为了让问题聚焦，采用了硬编码的方式来描述硬件信息——直接把寄存器地址写在代码里。</p></li><li><p><strong>01_device_tree_base</strong>：教你如何用设备树来替代硬编码。你会学习如何把硬件信息从驱动代码中剥离出来，放到设备树文件中，然后通过OF API在运行时读取这些信息。这是现代Linux驱动的标准做法。</p></li></ul><p>建议的学习顺序是：先完成00_chardev_base教程，再进入这套设备树教程。如果你已经有了一定的驱动开发经验，也可以直接从这套教程开始，但需要确保你已经理解了字符设备驱动的基础概念。</p><h2 id="学习路径规划" tabindex="-1">学习路径规划 <a class="header-anchor" href="#学习路径规划" aria-label="Permalink to &quot;学习路径规划&quot;">​</a></h2><p>这套教程的设计思路是&quot;从理论到实践，从基础到应用&quot;。</p><h3 id="完整学习路径-推荐新手" tabindex="-1">完整学习路径（推荐新手） <a class="header-anchor" href="#完整学习路径-推荐新手" aria-label="Permalink to &quot;完整学习路径（推荐新手）&quot;">​</a></h3><p>如果你是第一次接触设备树，建议按顺序学习所有章节：</p><h4 id="阶段一-基础理论-01-04章" tabindex="-1"><strong>阶段一：基础理论</strong>（01-04章） <a class="header-anchor" href="#阶段一-基础理论-01-04章" aria-label="Permalink to &quot;**阶段一：基础理论**（01-04章）&quot;">​</a></h4><p>这个阶段的目标是建立对设备树的完整认知，理解它是什么、为什么需要它、语法怎么写。</p><ol><li><strong><a href="./01_device_tree_introduction">01_device_tree_introduction.md</a></strong> - 设备树简介（30分钟）⭐</li><li><strong><a href="./02_dtc_deep_dive">02_dtc_deep_dive.md</a></strong> - DTC深入讲解（40分钟）</li><li><strong><a href="./03_device_tree_syntax">03_device_tree_syntax.md</a></strong> - 设备树语法详解（50分钟）⭐</li><li><strong><a href="./04_device_tree_history">04_device_tree_history.md</a></strong> - 设备树历史演进（25分钟）</li></ol><h4 id="阶段二-api学习与验证-05-06章" tabindex="-1"><strong>阶段二：API学习与验证</strong>（05-06章） <a class="header-anchor" href="#阶段二-api学习与验证-05-06章" aria-label="Permalink to &quot;**阶段二：API学习与验证**（05-06章）&quot;">​</a></h4><ol start="5"><li><strong><a href="./05_of_api_basics">05_of_api_basics.md</a></strong> - OF API基础（60分钟）⭐</li><li><strong><a href="./06_of_api_verification">06_of_api_verification.md</a></strong> - OF API验证（35分钟）</li></ol><h4 id="阶段三-实战应用-07-10章" tabindex="-1"><strong>阶段三：实战应用</strong>（07-10章） <a class="header-anchor" href="#阶段三-实战应用-07-10章" aria-label="Permalink to &quot;**阶段三：实战应用**（07-10章）&quot;">​</a></h4><ol start="7"><li><strong><a href="./07_driver_comparison">07_driver_comparison.md</a></strong> - 驱动代码对比（45分钟）</li><li><strong><a href="./08_device_tree_driver">08_device_tree_driver.md</a></strong> - 设备树驱动改造（70分钟）⭐</li><li><strong><a href="./09_board_dts_modification">09_board_dts_modification.md</a></strong> - 板级DTS修改实操（50分钟）</li><li><strong><a href="./10_complete_practice">10_complete_practice.md</a></strong> - 完整实战演练（80分钟）⭐</li></ol><h4 id="阶段四-编译机制-进阶·可选" tabindex="-1"><strong>阶段四：编译机制（进阶·可选）</strong> <a class="header-anchor" href="#阶段四-编译机制-进阶·可选" aria-label="Permalink to &quot;**阶段四：编译机制（进阶·可选）**&quot;">​</a></h4><p>面向项目维护者和想深入理解设备树编译链路的同学，新手可跳过，需要时再回来看：</p><ol start="11"><li><strong><a href="./11_compile_mechanism">11_compile_mechanism.md</a></strong> - 内核设备树编译机制深度解析（高级）</li><li><strong><a href="./12_compile_migration">12_compile_migration.md</a></strong> - 设备树编译机制迁移实践（中级）</li></ol><h3 id="快速路径-有经验开发者" tabindex="-1">快速路径（有经验开发者） <a class="header-anchor" href="#快速路径-有经验开发者" aria-label="Permalink to &quot;快速路径（有经验开发者）&quot;">​</a></h3><p>如果你已经有了一定的设备树基础，或者时间比较紧张，可以选择性地阅读重点章节：</p><ul><li><strong>必读章节</strong>：03、05、08、10</li><li><strong>选读章节</strong>：01、02、06、07、09</li><li><strong>可以跳过</strong>：04（历史章节）</li></ul><h2 id="章节目录" tabindex="-1">章节目录 <a class="header-anchor" href="#章节目录" aria-label="Permalink to &quot;章节目录&quot;">​</a></h2><h3 id="阶段一-基础理论" tabindex="-1">阶段一：基础理论 <a class="header-anchor" href="#阶段一-基础理论" aria-label="Permalink to &quot;阶段一：基础理论&quot;">​</a></h3>',27)),a(l,null,{default:r(()=>[a(i,{num:"01",href:"01_device_tree_introduction"},{default:r(()=>[...e[0]||(e[0]=[t("设备树简介",-1)])]),_:1}),a(i,{num:"02",href:"02_dtc_deep_dive"},{default:r(()=>[...e[1]||(e[1]=[t("DTC 深入讲解",-1)])]),_:1}),a(i,{num:"03",href:"03_device_tree_syntax"},{default:r(()=>[...e[2]||(e[2]=[t("设备树语法详解",-1)])]),_:1}),a(i,{num:"04",href:"04_device_tree_history"},{default:r(()=>[...e[3]||(e[3]=[t("设备树历史演进",-1)])]),_:1})]),_:1}),e[15]||(e[15]=o("h3",{id:"阶段二-api-学习与验证",tabindex:"-1"},[t("阶段二：API 学习与验证 "),o("a",{class:"header-anchor",href:"#阶段二-api-学习与验证","aria-label":'Permalink to "阶段二：API 学习与验证"'},"​")],-1)),a(l,null,{default:r(()=>[a(i,{num:"05",href:"05_of_api_basics"},{default:r(()=>[...e[4]||(e[4]=[t("OF API 基础",-1)])]),_:1}),a(i,{num:"06",href:"06_of_api_verification"},{default:r(()=>[...e[5]||(e[5]=[t("OF API 验证",-1)])]),_:1})]),_:1}),e[16]||(e[16]=o("h3",{id:"阶段三-实战应用",tabindex:"-1"},[t("阶段三：实战应用 "),o("a",{class:"header-anchor",href:"#阶段三-实战应用","aria-label":'Permalink to "阶段三：实战应用"'},"​")],-1)),a(l,null,{default:r(()=>[a(i,{num:"07",href:"07_driver_comparison"},{default:r(()=>[...e[6]||(e[6]=[t("驱动代码对比",-1)])]),_:1}),a(i,{num:"08",href:"08_device_tree_driver"},{default:r(()=>[...e[7]||(e[7]=[t("设备树驱动改造",-1)])]),_:1}),a(i,{num:"09",href:"09_board_dts_modification"},{default:r(()=>[...e[8]||(e[8]=[t("板级 DTS 修改实操",-1)])]),_:1}),a(i,{num:"10",href:"10_complete_practice"},{default:r(()=>[...e[9]||(e[9]=[t("完整实战演练",-1)])]),_:1})]),_:1}),e[17]||(e[17]=o("h3",{id:"阶段四-编译机制-进阶-·-可选",tabindex:"-1"},[t("阶段四：编译机制（进阶 · 可选） "),o("a",{class:"header-anchor",href:"#阶段四-编译机制-进阶-·-可选","aria-label":'Permalink to "阶段四：编译机制（进阶 · 可选）"'},"​")],-1)),a(l,null,{default:r(()=>[a(i,{num:"11",href:"11_compile_mechanism"},{default:r(()=>[...e[10]||(e[10]=[t("内核设备树编译机制深度解析",-1)])]),_:1}),a(i,{num:"12",href:"12_compile_migration"},{default:r(()=>[...e[11]||(e[11]=[t("设备树编译机制迁移实践",-1)])]),_:1})]),_:1}),e[18]||(e[18]=d('<div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>理解设备树的设计动机和语法规范，掌握 OF API 读取硬件信息，完成从硬编码驱动到设备树驱动的完整改造。</p></div><div class="info custom-block"><p class="custom-block-title">前置知识</p><p>建议先完成 <a href="./../00_chardev_base/">字符设备驱动教程</a> · C 语言基础 · Linux 内核模块概念</p></div><details class="details custom-block"><summary>延伸阅读</summary><ul><li><a href="https://www.devicetree.org/" target="_blank" rel="noreferrer">设备树规范</a></li><li><a href="https://www.kernel.org/doc/html/latest/devicetree/" target="_blank" rel="noreferrer">内核设备树文档</a></li><li><a href="https://lwn.net/Kernel/LDD3/" target="_blank" rel="noreferrer">Linux 设备驱动（LDD3）</a></li></ul></details><h2 id="实验环境" tabindex="-1">实验环境 <a class="header-anchor" href="#实验环境" aria-label="Permalink to &quot;实验环境&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><ul><li><strong>推荐</strong>：i.MX 6ULL系列开发板（如Alpha开发板）</li><li><strong>兼容</strong>：其他ARM Cortex-A系列开发板</li></ul><h3 id="软件环境" tabindex="-1">软件环境 <a class="header-anchor" href="#软件环境" aria-label="Permalink to &quot;软件环境&quot;">​</a></h3><ul><li><strong>操作系统</strong>：Linux（推荐Ubuntu 20.04或更高版本）</li><li><strong>内核版本</strong>： <ul><li>Linux 6.12.49 (linux-imx)</li><li>Linux 7.1.0 (mainline)</li></ul></li><li><strong>交叉编译工具链</strong>：arm-linux-gnueabhif-gcc</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-设备树文件必须从零开始写吗" tabindex="-1">Q: 设备树文件必须从零开始写吗？ <a class="header-anchor" href="#q-设备树文件必须从零开始写吗" aria-label="Permalink to &quot;Q: 设备树文件必须从零开始写吗？&quot;">​</a></h3><p>A: 完全不需要。在实际开发中，我们通常是修改芯片厂商提供的参考DTS文件。从零编写整份设备树文件的情况非常少见，除非你在设计一块全新的板子。所以本教程的重点是&quot;读懂和修改&quot;，而不是&quot;从零编写&quot;。</p><h3 id="q-设备树和dts、dtb是什么关系" tabindex="-1">Q: 设备树和DTS、DTB是什么关系？ <a class="header-anchor" href="#q-设备树和dts、dtb是什么关系" aria-label="Permalink to &quot;Q: 设备树和DTS、DTB是什么关系？&quot;">​</a></h3><p>A: DTS是设备树源文件（文本格式），DTB是编译后的二进制文件。内核启动时读取的是DTB文件，而我们编辑的是DTS文件。DTC编译器负责把DTS转换成DTB。</p><h3 id="q-为什么有些属性名前面有井号-比如-address-cells" tabindex="-1">Q: 为什么有些属性名前面有井号，比如#address-cells？ <a class="header-anchor" href="#q-为什么有些属性名前面有井号-比如-address-cells" aria-label="Permalink to &quot;Q: 为什么有些属性名前面有井号，比如#address-cells？&quot;">​</a></h3><p>A: 井号开头的属性是&quot;元属性&quot;，它们描述的是如何解析其他属性，而不是设备本身的属性。#address-cells告诉解析器如何解析reg属性的地址部分，#size-cells告诉解析器如何解析reg属性的大小部分。</p><h3 id="q-compatible属性到底有什么用" tabindex="-1">Q: compatible属性到底有什么用？ <a class="header-anchor" href="#q-compatible属性到底有什么用" aria-label="Permalink to &quot;Q: compatible属性到底有什么用？&quot;">​</a></h3><p>A: compatible属性是驱动和设备匹配的关键。内核通过比较设备树中的compatible属性和驱动代码中的compatible字符串，来决定为这个设备加载哪个驱动。所以它的命名必须准确，通常格式是&quot;厂商,型号&quot;，如&quot;fsl,imx6ull&quot;。</p><h3 id="q-改了设备树文件但是没生效怎么办" tabindex="-1">Q: 改了设备树文件但是没生效怎么办？ <a class="header-anchor" href="#q-改了设备树文件但是没生效怎么办" aria-label="Permalink to &quot;Q: 改了设备树文件但是没生效怎么办？&quot;">​</a></h3><p>A: 这是一个常见问题。首先确认DTB文件是否重新编译了，其次确认板子加载的是不是新的DTB文件，最后可以通过/proc/device-tree查看内核实际使用的设备树内容。09_board_dts_modification.md章节有详细的排查方法。</p><h2 id="继续学习" tabindex="-1">继续学习 <a class="header-anchor" href="#继续学习" aria-label="Permalink to &quot;继续学习&quot;">​</a></h2>',20)),a(l,{variant:"sub"},{default:r(()=>[a(i,{href:"../00_chardev_base/",variant:"sub"},{default:r(()=>[...e[12]||(e[12]=[t("← 字符设备驱动教程",-1)])]),_:1}),a(i,{href:"../../",variant:"sub"},{default:r(()=>[...e[13]||(e[13]=[t("返回驱动开发 →",-1)])]),_:1})]),_:1})])}const P=_(m,[["render",p]]);export{x as __pageData,P as default};
